import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{a as i,i as a,n as o,r as s,t as c}from"./chunks/javadoc.By8MmAW1.js";const l=JSON.parse(`{"title":"Generare le Sorgenti in IntelliJ IDEA","description":"Una guida alla generazione delle risorse di Minecraft in IntelliJ IDEA.","frontmatter":{"title":"Generare le Sorgenti in IntelliJ IDEA","description":"Una guida alla generazione delle risorse di Minecraft in IntelliJ IDEA.","authors":["dicedpixels"],"prev":{"text":"Avviare il Gioco in IntelliJ IDEA","link":"./launching-the-game"},"next":{"text":"Costruire una mod in IntelliJ IDEA","link":"./building-a-mod"},"files":[]},"headers":[],"relativePath":"it_it/develop/getting-started/intellij-idea/generating-sources.md","filePath":"translated/it_it/develop/getting-started/intellij-idea/generating-sources.md","lastUpdated":1774101324000}`);var u={name:`it_it/develop/getting-started/intellij-idea/generating-sources.md`};function d(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Generare le Sorgenti in IntelliJ IDEA <a class="header-anchor" href="#h1" aria-label="Permalink to “Generare le Sorgenti in IntelliJ IDEA”">​</a></h1><p>La toolchain Fabric ti permette di accedere al codice sorgente di Minecraft generandolo localmente, e puoi usare IntelliJ IDEA per navigarci comodamente. Per generare le sorgenti, bisogna eseguire l&#39;attività Gradle <code>genSources</code>.</p><p>Questo si può fare dal pannello Gradle, eseguendo l&#39;attività <code>genSources</code> in <strong>Tasks</strong> &gt; <strong><code>fabric</code></strong>: <img src="/assets/develop/getting-started/intellij/gradle-gensources.png" alt="Attività genSources nel pannello Gradle" loading="lazy"></p><p>Oppure puoi eseguire il comando dal terminale:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> genSources</span></span></code></pre></div><p><img src="/assets/develop/getting-started/intellij/terminal-gensources.png" alt="Attività genSources nel terminale" loading="lazy"></p><h2 id="attaching-sources" tabindex="-1">Allegare le sorgenti <a class="header-anchor" href="#attaching-sources" aria-label="Permalink to “Allegare le sorgenti”">​</a></h2><p>Per IntelliJ serve un passaggio ulteriore, ovvero allegare le sorgenti generate al progetto.</p><p>Per far ciò, apri qualsiasi classe di Minecraft. Puoi fare <kbd>Ctrl</kbd> + Clic per raggiungere la definizione, che mostrerà una classe, oppure usa &quot;Search everywhere&quot; per aprirne una.</p><p>Per esempio, apriamo <code>MinecraftServer.class</code>. Dovresti ora vedere un banner blu in cima, con un link &quot;<strong>Choose Sources...</strong>&quot;.</p><p><img src="/assets/develop/getting-started/intellij/choose-sources.png" alt="Pulsante Choose Sources" loading="lazy"></p><p>Clicca su &quot;<strong>Choose Sources...</strong>&quot; per aprire una finestra di selezione file. La finestra si apre in automatico nella posizione dove sono generate le fonti.</p><p>Seleziona il file che finisce per <strong><code>-sources</code></strong> e premi <strong>Open</strong> per confermare la selezione.</p><p><img src="/assets/develop/getting-started/intellij/choose-sources-dialog.png" alt="Finestra per scegliere le sorgenti" loading="lazy"></p><p>Dovresti ora poter cercare i riferimenti. Se stai usando dei mapping che contengono Javadoc, per esempio <a href="https://parchmentmc.org/" target="_blank" rel="noreferrer">Parchment</a> (per i mapping di Mojang) o Yarn, dovresti anche vedere i Javadoc.</p><p><img src="/assets/develop/getting-started/intellij/javadoc.png" alt="Commenti Javadoc nelle sorgenti" loading="lazy"></p>`,16)]])}var f=r(u,[[`render`,d]]);export{l as __pageData,f as default};